UPDATE financial_information
k3_id = CASE supplier_number
WHEN #{item.supplierNumber} THEN #{item.k3Id}
ELSE k3_id END, nation = CASE supplier_number
WHEN #{item.supplierNumber} THEN #{item.nation}
ELSE nation END, bank_account = CASE supplier_number
WHEN #{item.supplierNumber} THEN #{item.bankAccount}
ELSE bank_account END, account_name = CASE supplier_number
WHEN #{item.supplierNumber} THEN #{item.accountName}
ELSE account_name END, receiving_bank = CASE supplier_number
WHEN #{item.supplierNumber} THEN #{item.receivingBank}
ELSE receiving_bank END, bank_address = CASE supplier_number
WHEN #{item.supplierNumber} THEN #{item.bankAddress}
ELSE bank_address END, opening_bank = CASE supplier_number
WHEN #{item.supplierNumber} THEN #{item.openingBank}
ELSE opening_bank END, updated_at = CASE supplier_number
WHEN #{item.supplierNumber} THEN NOW()
ELSE updated_at END
WHERE supplier_number IN
#{item.supplierNumber}
